import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { AppState, Customer, Transaction, TransactionType } from './types';
import { TRANSLATIONS, COLORS } from './constants';
import { dbService } from './services/db';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import CustomerDetail from './components/CustomerDetail';
import ReportView from './components/ReportView';
import Navbar from './components/Navbar';
import AddTransactionModal from './components/AddTransactionModal';
import AddCustomerModal from './components/AddCustomerModal';
import EditTransactionModal from './components/EditTransactionModal';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'customers' | 'reports'>('home');
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | null>(null);
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [isCustomerModalOpen, setIsCustomerModalOpen] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [txModalType, setTxModalType] = useState<TransactionType>('CREDIT');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const [state, setState] = useState<AppState>(() => dbService.loadData());

  const t = TRANSLATIONS.bn;

  // Sync with localStorage
  useEffect(() => {
    dbService.saveData(state);
  }, [state]);

  const addCustomer = (name: string, phone: string) => {
    const newCustomer: Customer = {
      id: crypto.randomUUID(),
      name,
      phone,
      balance: 0,
      lastUpdated: Date.now(),
    };
    setState(prev => ({
      ...prev,
      customers: [...prev.customers, newCustomer]
    }));
    setIsCustomerModalOpen(false);
  };

  const addTransaction = (customerId: string, amount: number, type: TransactionType, note?: string, date?: string) => {
    const newTx: Transaction = {
      id: crypto.randomUUID(),
      customerId,
      amount,
      type,
      note,
      date: date || new Date().toISOString().split('T')[0],
      createdAt: Date.now(),
    };

    setState(prev => {
      const nextTransactions = [...prev.transactions, newTx];
      return dbService.calculateBalances(prev.customers, nextTransactions);
    });
    setIsTxModalOpen(false);
  };

  const handleEditTx = (id: string, updates: Partial<Transaction>) => {
    setState(prev => {
      const nextTransactions = prev.transactions.map(t => t.id === id ? { ...t, ...updates } : t);
      return dbService.calculateBalances(prev.customers, nextTransactions);
    });
    setIsEditModalOpen(false);
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setState(prev => {
      const nextTransactions = prev.transactions.filter(t => t.id !== id);
      return dbService.calculateBalances(prev.customers, nextTransactions);
    });
  };

  const openEditModal = (tx: Transaction) => {
    setEditingTransaction(tx);
    setIsEditModalOpen(true);
  };

  const selectedCustomer = useMemo(() => 
    state.customers.find(c => c.id === selectedCustomerId) || null,
  [selectedCustomerId, state.customers]);

  const renderContent = () => {
    if (selectedCustomerId) {
      return (
        <CustomerDetail 
          customer={selectedCustomer!} 
          transactions={state.transactions.filter(t => t.customerId === selectedCustomerId)}
          onBack={() => setSelectedCustomerId(null)}
          onAddTx={(type) => {
            setTxModalType(type);
            setIsTxModalOpen(true);
          }}
          onEditTx={openEditModal}
          onDeleteTx={deleteTransaction}
        />
      );
    }

    switch (activeTab) {
      case 'home':
        return (
          <Dashboard 
            state={state} 
            onQuickAdd={(type) => {
              setTxModalType(type);
              setIsTxModalOpen(true);
            }}
          />
        );
      case 'customers':
        return (
          <CustomerList 
            customers={state.customers} 
            onSelectCustomer={setSelectedCustomerId}
            onAddCustomer={() => setIsCustomerModalOpen(true)}
          />
        );
      case 'reports':
        return (
          <ReportView 
            transactions={state.transactions}
            customers={state.customers}
            onEditTx={openEditModal}
            onDeleteTx={deleteTransaction}
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex flex-col min-h-screen max-w-md mx-auto bg-gray-50 shadow-xl overflow-hidden relative">
      <main className="flex-1 overflow-y-auto pb-24">
        {renderContent()}
      </main>

      <Navbar activeTab={activeTab} setActiveTab={setActiveTab} />

      <AddTransactionModal 
        isOpen={isTxModalOpen}
        onClose={() => setIsTxModalOpen(false)}
        type={txModalType}
        customers={state.customers}
        preSelectedCustomerId={selectedCustomerId || undefined}
        onSubmit={addTransaction}
      />

      <AddCustomerModal 
        isOpen={isCustomerModalOpen}
        onClose={() => setIsCustomerModalOpen(false)}
        onSubmit={addCustomer}
      />

      <EditTransactionModal 
        isOpen={isEditModalOpen}
        onClose={() => setIsEditModalOpen(false)}
        transaction={editingTransaction}
        customers={state.customers}
        onSubmit={handleEditTx}
      />
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Transaction, Customer } from '../types';
import { TRANSLATIONS } from '../constants';

interface ReportViewProps {
  transactions: Transaction[];
  customers: Customer[];
  onEditTx: (tx: Transaction) => void;
  onDeleteTx: (id: string) => void;
}

const ReportView: React.FC<ReportViewProps> = ({ transactions, customers, onEditTx, onDeleteTx }) => {
  const t = TRANSLATIONS.bn;
  const [filter, setFilter] = useState<'today' | 'month' | 'all'>('all');

  const filteredTxs = useMemo(() => {
    const now = new Date();
    const todayStr = now.toISOString().split('T')[0];
    const monthStr = now.toISOString().substring(0, 7);

    return transactions.filter(tx => {
      if (filter === 'today') return tx.date === todayStr;
      if (filter === 'month') return tx.date.startsWith(monthStr);
      return true;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, filter]);

  const stats = useMemo(() => {
    const totalCredit = filteredTxs.filter(t => t.type === 'CREDIT').reduce((a, b) => a + b.amount, 0);
    const totalPayment = filteredTxs.filter(t => t.type === 'PAYMENT').reduce((a, b) => a + b.amount, 0);
    return { totalCredit, totalPayment, net: totalPayment - totalCredit };
  }, [filteredTxs]);

  const getCustomerName = (id: string) => customers.find(c => c.id === id)?.name || 'Unknown';

  return (
    <div className="p-4 space-y-4 animate-in fade-in duration-300">
      <h2 className="text-2xl font-bold text-gray-800">{t.reports}</h2>

      <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-gray-100">
        {(['all', 'month', 'today'] as const).map((type) => (
          <button
            key={type}
            onClick={() => setFilter(type)}
            className={`flex-1 py-2 text-sm font-bold rounded-xl transition-all ${
              filter === type ? 'bg-[#006A4E] text-white shadow-md' : 'text-gray-500'
            }`}
          >
            {type === 'all' ? 'সব সময়' : (type === 'month' ? 'এই মাস' : 'আজ')}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-2 gap-3">
        <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
          <p className="text-xs text-red-600 font-bold uppercase tracking-tight">মোট বাকি</p>
          <p className="text-xl font-bold text-red-700">৳ {stats.totalCredit.toLocaleString()}</p>
        </div>
        <div className="bg-green-50 p-4 rounded-2xl border border-green-100">
          <p className="text-xs text-green-600 font-bold uppercase tracking-tight">মোট জমা</p>
          <p className="text-xl font-bold text-green-700">৳ {stats.totalPayment.toLocaleString()}</p>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-4 border-b border-gray-50 bg-gray-50/50 flex justify-between items-center">
          <h3 className="font-bold text-gray-700">লেনদেন তালিকা ({filteredTxs.length})</h3>
          <span className={`text-sm font-bold ${stats.net >= 0 ? 'text-green-600' : 'text-red-600'}`}>
            নেট: ৳ {Math.abs(stats.net).toLocaleString()}
          </span>
        </div>

        <div className="divide-y divide-gray-50">
          {filteredTxs.length > 0 ? filteredTxs.map(tx => (
            <div 
              key={tx.id} 
              className="p-4 flex justify-between items-center hover:bg-gray-50 transition-colors group cursor-pointer active:bg-gray-100"
              onClick={() => onEditTx(tx)}
            >
              <div>
                <p className="font-bold text-gray-800">{getCustomerName(tx.customerId)}</p>
                <p className="text-xs text-gray-400">{tx.date} • {tx.note || 'নোট নেই'}</p>
              </div>
              <div className="flex items-center gap-4">
                <p className={`font-bold ${tx.type === 'CREDIT' ? 'text-red-600' : 'text-green-600'}`}>
                  ৳ {tx.amount.toLocaleString()}
                </p>
                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    if(confirm(t.confirmDelete)) onDeleteTx(tx.id);
                  }}
                  className="p-2 text-gray-300 hover:text-red-500 transition-colors"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
                  </svg>
                </button>
              </div>
            </div>
          )) : (
            <div className="py-10 text-center text-gray-400 text-sm">কোনো ডাটা পাওয়া যায়নি</div>
          )}
        </div>
      </div>
      <p className="text-center text-[10px] text-gray-300 font-bold uppercase tracking-widest mt-2">যেকোনো লেনদেন সংশোধন করতে উপরে ট্যাপ করুন</p>
    </div>
  );
};

